// Pre-process: works for all source types (PDF text comes in as json.text,
// web and Excel already produce json.text in their extractors)
const rawText = $input.first().json.text || $input.first().json.data || '';
const upstream = $input.first().json;

// Truncate to 12,000 chars for LLM submission
// In production: intelligent section detection isolates T&C clauses
const truncated = rawText.substring(0, 12000);

// MD5 hash for change detection
const hash = require('crypto')
  .createHash('md5')
  .update(rawText)
  .digest('hex');

return [{
  json: {
    processedText: truncated,
    documentHash: hash,
    supplier: upstream.supplier || 'Unknown',
    pickupCountry: upstream.pickupCountry || 'XX',
    sourceUrl: upstream.url || 'local',
    sourceType: upstream.sourceType || 'pdf',
    ingestedAt: new Date().toISOString(),
    characterCount: rawText.length
  }
}];

// Parse LLM JSON output and apply validation rules
const llmResponse = $input.first().json.message?.content || $input.first().json.text || '{}';
const upstream = $('Pre-process & Hash Document').first().json;

let extracted;
try {
  // Strip markdown fences if present (defensive)
  const cleaned = llmResponse.replace(/```json\n?|```\n?/g, '').trim();
  extracted = JSON.parse(cleaned);
} catch(e) {
  extracted = {
    tpl_amount: {value: null, confidence: 'LOW', source_text: null},
    grace_period_minutes: {value: null, confidence: 'LOW', source_text: null},
    licence_rules: {value: null, confidence: 'LOW', source_text: null},
    payment_rules: {value: null, confidence: 'LOW', source_text: null},
    cross_border_conditions: {value: null, confidence: 'LOW', source_text: null}
  };
}

// Validation rules
const CONFIDENCE_ORDER = ['HIGH', 'MEDIUM', 'LOW'];
const validationFlags = [];

// Grace period sanity check
if (extracted.grace_period_minutes?.value !== null) {
  const gp = parseInt(extracted.grace_period_minutes.value);
  if (isNaN(gp) || gp < 0 || gp > 480) {
    validationFlags.push('grace_period_out_of_range');
    extracted.grace_period_minutes.confidence = 'LOW';
  }
}

// Count low confidence fields
const lowConfidenceFields = Object.entries(extracted)
  .filter(([k, v]) => v?.confidence === 'LOW')
  .map(([k]) => k);

// Determine overall record status
const requiresHumanReview = lowConfidenceFields.length >= 2 || validationFlags.length > 0;
const overallConfidence = lowConfidenceFields.length === 0 ? 'HIGH' :
  lowConfidenceFields.length <= 2 ? 'MEDIUM' : 'LOW';

// Check if TPL is STATUTORY_MINIMUM — needs COB lookup
const tplNeedsCobLookup = extracted.tpl_amount?.value === 'STATUTORY_MINIMUM' ||
  extracted.tpl_amount?.value === null;

return [{
  json: {
    supplier: upstream.supplier,
    pickupCountry: upstream.pickupCountry,
    sourceUrl: upstream.sourceUrl,
    documentHash: upstream.documentHash,
    ingestedAt: upstream.ingestedAt,
    extractedAt: new Date().toISOString(),
    extractionModel: 'gpt-4o',
    fields: extracted,
    overallConfidence,
    requiresHumanReview,
    lowConfidenceFields,
    validationFlags,
    tplNeedsCobLookup
  }
}];

// COB 2026 statutory minimum TPL lookup table
// Source: Council of Bureaux, Minimum Amount of Coverage 2026 (April 2026 edition)
// Disclaimer: Figures provided for information only. COB assumes no responsibility for accuracy.
const COB_2026 = {
  'DE': { personal_injury: '€7,500,000', property_damage: '€1,300,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'ES': { personal_injury: '€70,000,000', property_damage: '€15,000,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'IT': { personal_injury: '€6,450,000', property_damage: '€1,300,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'GB': { personal_injury: '£1,200,000', property_damage: '£1,200,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'NO': { personal_injury: 'Unlimited', property_damage: '€8,484,643', data_date: 'Dec-25', confidence: 'HIGH' },
  'CH': { personal_injury: 'CHF 5,000,000 per claim', property_damage: null, data_date: 'Nov-24', confidence: 'HIGH' },
  'AT': { personal_injury: null, property_damage: null, data_date: 'Oct-21', confidence: 'NONE', note: 'No data submitted to COB — manual verification required' },
  'FR': { personal_injury: 'Unlimited', property_damage: 'Unlimited', data_date: 'Mar-22', confidence: 'MEDIUM', note: 'Unlimited — not displayable as a numeric value' },
  'NL': { personal_injury: '€6,070,000', property_damage: '€1,220,000', data_date: 'Nov-20', confidence: 'MEDIUM', note: 'Stale — data from Nov-20' },
  'BE': { personal_injury: '€129,550,507', property_damage: 'Unlimited', data_date: 'Dec-25', confidence: 'HIGH' },
  'PL': { personal_injury: '€5,210,000', property_damage: '€1,050,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'PT': { personal_injury: '€6,450,000', property_damage: '€1,300,000', data_date: 'Dec-25', confidence: 'HIGH' }
};

const country = $json.pickupCountry?.toUpperCase();
const cobData = COB_2026[country];

let tplResolved;
if (cobData && cobData.confidence !== 'NONE') {
  tplResolved = {
    value: `Personal injury: ${cobData.personal_injury} | Property damage: ${cobData.property_damage || 'see COB'}`,
    confidence: cobData.confidence,
    source: `COB Minimum Amount of Coverage 2026 (data date: ${cobData.data_date})`,
    source_url: 'https://www.cobx.org/sites/default/files/2026-04/MinimumAmountOfCoverage%202026.pdf',
    disclaimer: 'Figures provided for information only. COB assumes no responsibility for accuracy or future changes.',
    note: cobData.note || null
  };
} else {
  tplResolved = {
    value: null,
    confidence: 'NONE',
    source: 'COB 2026',
    source_url: 'https://www.cobx.org/sites/default/files/2026-04/MinimumAmountOfCoverage%202026.pdf',
    disclaimer: 'No COB data available for this country — manual verification required.',
    note: cobData?.note || 'Country not found in COB 2026 dataset'
  };
}

// Merge COB result into the fields
const updatedFields = { ...$json.fields };
updatedFields.tpl_amount = {
  ...updatedFields.tpl_amount,
  ...tplResolved,
  resolution_method: 'COB_LOOKUP'
};

return [{ json: { ...$json, fields: updatedFields, tplResolvedViaCob: true } }];

